    "reserva-emergencia",
    "projetos-vida",
    "independencia-financeira"
  ];

  const tipo =
    valorFinal < 0
      ? "despesa"
      : categoriasNeutras.includes(item.c)
        ? "neutro"
        : "receita";

  // ========================================
  // RETORNO FINAL
  // ========================================

  return {
    json: {
      account_id: accountId,
