const items = $input.all();

const result = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  if (!item.binary || !item.binary.data) {
    throw new Error(`Não encontrei o arquivo binário no campo "data" do item ${i}.`);
  }

  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');

  result.push({
    json: {
      ...item.json,
      pdfBase64: buffer.toString('base64'),
      fileName: item.binary.data.fileName,
      mimeType: item.binary.data.mimeType,
    },
    binary: item.binary,
  });
}

return result;

const input = $input.first().json;

if (!input.pages || !Array.isArray(input.pages)) {
  throw new Error('Não encontrei o campo pages no retorno da Mistral.');
}

function injectTablesIntoMarkdown(page) {
  let text = page.markdown || '';

  const tables = page.tables || [];

  for (const table of tables) {
    if (!table.id || !table.content) continue;

    const markdownRef = `[${table.id}](${table.id})`;

    text = text.replaceAll(
      markdownRef,
      `\n${table.content}\n`
    );
  }

  return text;
}

const extractedText = input.pages
  .sort((a, b) => a.index - b.index)
  .map(page => injectTablesIntoMarkdown(page))
  .join('\n\n--- QUEBRA DE PÁGINA ---\n\n');

return [
  {
    json: {
      extractedText
    }
  }
];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

/**
 * =========================================
 * CORRETOR E VALIDOR DE DATAS DE TRANSAÇÕES
 * =========================================
 *
 * Objetivo:
 * - Validar datas extraídas pela IA
 * - Corrigir automaticamente o ano quando necessário
 * - Evitar datas inválidas
 * - NÃO alterar meses com base em parcelamento
 *
 * Exemplo de correção:
 * Vencimento da fatura: 08/02/2026
 * Compra: 25/12
 * Resultado esperado:
 * 25/12/2025
 */

/**
 * Faz parse seguro de uma data brasileira (DD/MM/YYYY)
 * e valida se ela realmente existe.
 */
function parseDateBR(dateStr) {

  // Divide a string por "/"
  // Ex: "25/12/2025" -> [25, 12, 2025]
  const parts = String(dateStr || '')
    .split('/')
    .map(Number);

  // Se não tiver exatamente 3 partes,
  // a data é inválida
  if (parts.length !== 3) {
    return null;
  }

  const [day, month, year] = parts;

  // Validação básica:
  // impede valores vazios ou zero
  if (!day || !month || !year) {
    return null;
  }

  // Cria objeto Date do JavaScript
  // OBS:
  // mês começa em 0 no JS
  const date = new Date(year, month - 1, day);

  /**
   * Validação FORTE contra datas inválidas.
   *
   * O JS aceita:
   * new Date(2026, 1, 31)
   * e transforma automaticamente em:
   * 03/03/2026
   *
   * Então precisamos confirmar se:
   * - ano continua igual
   * - mês continua igual
   * - dia continua igual
   */
  const isValid =
    date.getFullYear() === year &&
    date.getMonth() === month - 1 &&
    date.getDate() === day;

  // Exemplos que cairiam aqui:
  // 31/02/2026
  // 29/02/2026 (ano não bissexto)
  if (!isValid) {
    return null;
  }

  return date;
}

/**
 * Converte um objeto Date novamente
 * para formato brasileiro DD/MM/YYYY
 */
function formatDateBR(date) {

  // Garante 2 dígitos
  const day = String(date.getDate()).padStart(2, '0');

  // Mês no JS começa em 0,
  // então somamos +1
  const month = String(date.getMonth() + 1)
    .padStart(2, '0');

  const year = date.getFullYear();

  return `${day}/${month}/${year}`;
}

/**
 * Tenta identificar parcelamento
 * vindo do campo "p" ou da descrição.
 *
 * Exemplos:
 * "04/12"
 * "PARC 02/06"
 */
function getInstallmentFromTransaction(transaction) {

  /**
   * ============================
   * 1. TENTA PELO CAMPO "p"
   * ============================
   */
  const fromP = transaction.p;

  if (fromP) {

    // Procura padrão XX/YY
    const matchP = String(fromP)
      .match(/(\d{1,2})\/(\d{1,2})/);

    if (matchP) {

      const current = Number(matchP[1]);
      const total = Number(matchP[2]);

      // Validação básica do parcelamento
      if (
        current &&
        total &&
        total >= 2 &&
        current <= total
      ) {
        return { current, total };
      }
    }
  }

  /**
   * ===================================
   * 2. TENTA PELA DESCRIÇÃO DA COMPRA
   * ===================================
   */
  const fromText = transaction.t;

  if (fromText) {

    const matchText = String(fromText)
      .match(/(\d{1,2})\/(\d{1,2})/);

    if (matchText) {

      const current = Number(matchText[1]);
      const total = Number(matchText[2]);

      if (
        current &&
        total &&
        total >= 2 &&
        current <= total
      ) {
        return { current, total };
      }
    }
  }

  // Nenhum parcelamento encontrado
  return null;
}

/**
 * Extrai a data de vencimento
 * diretamente do texto OCR/PDF.
 */
function getDueDateFromExtractedText() {

  let extractedText = '';

  /**
   * Tenta pegar o texto bruto
   * do node anterior
   */
  try {

    extractedText =
      $('Extrai PDF, CSV e XLSX')
        .item
        .json
        .extractedText || '';

  } catch (error) {

    extractedText = '';
  }

  /**
   * Regex aceitos para vencimento
   */
  const patterns = [

    /Vencimento:\s*(\d{2}\/\d{2}\/\d{4})/i,

    /Com vencimento em:\s*(\d{2}\/\d{2}\/\d{4})/i,

    /Data de Vencimento\s*(\d{2}\/\d{2}\/\d{4})/i,

    /Vencimento\s*(\d{2}\/\d{2}\/\d{4})/i,
  ];

  // Testa todos os padrões
  for (const pattern of patterns) {

    const match =
      String(extractedText).match(pattern);

    if (match) {
      return match[1];
    }
  }

  // Nenhuma data encontrada
  return null;
}

/**
 * Corrige automaticamente o ano
 * quando a compra pertence ao ano anterior.
 *
 * Exemplo:
 *
 * vencimento:
 * 08/02/2026
 *
 * compra:
 * 25/12
 *
 * resultado:
 * 25/12/2025
 */
function adjustOriginalYearIfNeeded(
  dateStr,
  dueDateStr
) {

  // Se faltar alguma data,
  // retorna original
  if (!dateStr || !dueDateStr) {
    return dateStr;
  }

  const dateParts =
    String(dateStr)
      .split('/')
      .map(Number);

  const dueParts =
    String(dueDateStr)
      .split('/')
      .map(Number);

  // Estrutura inválida
  if (
    dateParts.length !== 3 ||
    dueParts.length !== 3
  ) {
    return dateStr;
  }

  const [day, month] = dateParts;

  const [, dueMonth, dueYear] = dueParts;

  // Segurança extra
  if (
    !day ||
    !month ||
    !dueMonth ||
    !dueYear
  ) {
    return dateStr;
  }

  /**
   * REGRA:
   *
   * Se o mês da transação
   * for MAIOR que o mês do vencimento,
   * significa que pertence ao ano anterior.
   *
   * Ex:
   * vencimento fevereiro/2026
   * compra dezembro
   * => dezembro/2025
   */
  const correctedYear =
    month > dueMonth
      ? dueYear - 1
      : dueYear;

  return `${String(day).padStart(2, '0')}/${String(month).padStart(2, '0')}/${correctedYear}`;
}

/**
 * Corrige e valida a data
 * de uma transação individual.
 */
function correctTransactionDate(
  transaction,
  dueDateStr
) {

  // Se não existir data,
  // retorna original
  if (!transaction.d) {
    return transaction;
  }

  /**
   * Ajusta possível problema de ano
   */
  const correctedDateStr =
    adjustOriginalYearIfNeeded(
      transaction.d,
      dueDateStr
    );

  /**
   * Faz parse + validação forte
   */
  const parsedDate =
    parseDateBR(correctedDateStr);

  /**
   * Se data inválida:
   * - mantém original
   * - adiciona flag de erro
   */
  if (!parsedDate) {

    return {
      ...transaction,

      invalid_date: true,

      original_date: transaction.d,
    };
  }

  /**
   * IMPORTANTE:
   *
   * NÃO somamos meses com base
   * no parcelamento.
   *
   * A IA já retorna a competência correta.
   */
  return {
    ...transaction,

    d: formatDateBR(parsedDate),
  };
}

/**
 * Corrige todas as transações
 * do array
 */
function correctArray(array, dueDateStr) {

  return array.map(transaction =>
    correctTransactionDate(
      transaction,
      dueDateStr
    )
  );
}

/**
 * ====================================
 * EXECUÇÃO PRINCIPAL DO NODE
 * ====================================
 */

// Extrai vencimento da fatura
const dueDateStr =
  getDueDateFromExtractedText();

// Recebe todos os itens do n8n
const items = $input.all();

/**
 * Processa cada item individualmente
 */
return items.map(item => {

  const json = item.json;

  /**
   * Caso:
   * { output: [...] }
   */
  if (Array.isArray(json.output)) {

    return {
      json: {
        ...json,

        output: correctArray(
          json.output,
          dueDateStr
        ),
      },
    };
  }

  /**
   * Caso:
   * item já seja array puro
   */
  if (Array.isArray(json)) {

    return {
      json: correctArray(
        json,
        dueDateStr
      ),
    };
  }

  /**
   * Caso:
   * transação única
   */
  return {
    json: correctTransactionDate(
      json,
      dueDateStr
    ),
  };
});

