/**
 * NORMALIZADOR UNIVERSAL V6.0 - BLINDADO
 *
 * Objetivo:
 * Padronizar as transações extraídas pela IA para um formato único
 * utilizado no sistema financeiro.
 *
 * O código:
 * - aceita tanto JSON estruturado quanto texto bruto da IA;
 * - tenta recuperar JSON quebrado;
 * - normaliza datas e valores;
 * - remove duplicidades de parcelamento;
 * - classifica transações;
 * - remove linhas de resumo/ruído.
 */


// ======================================================
// CONFIGURAÇÕES INICIAIS
// ======================================================

// Ano atual usado como fallback quando a transação não possui ano
const anoAtual = new Date().getFullYear();

// Informações da conta/banco recebidas via webhook
let infoConta = {
  id: "",
  nome: "Banco - Conta"
};


// ======================================================
// 1. CAPTURA DADOS DO WEBHOOK
// ======================================================

/**
 * Tenta obter:
 * - accountId
 * - nome do banco
 * - nome da conta
 *
 * vindos do webhook do Supabase.
 */
try {

  const webhookNode = $("Recebe link do Supabase Storage").first();

  if (
    webhookNode &&
    webhookNode.json &&
    webhookNode.json.body
  ) {

      infoConta.id =
        webhookNode.json.body.accountId || "";

      infoConta.nome =
        `${webhookNode.json.body.bankName || "Banco"} - ${webhookNode.json.body.accountName || "Conta"}`;
  }

} catch (e) {

  // Se falhar, apenas mantém valores padrão
}


// ======================================================
// ARRAYS AUXILIARES
// ======================================================

// Resultado final já normalizado
const resultadosFinais = [];

/**
 * Mapa utilizado para evitar duplicidade de parcelamentos.
 *
 * Exemplo:
 * "NETFLIX_50_12" => parcela atual vista
 */
const parcelamentosVistos = new Map();


// Relatório de erros e avisos
const relatorio_erros = [];


// ======================================================
// 2. LOOP PRINCIPAL DOS ITENS RETORNADOS PELA IA
// ======================================================

const todosOsItens = $input.all();

for (let i = 0; i < todosOsItens.length; i++) {

    // Item atual retornado pela IA
    let item = todosOsItens[i].json;

    // Array de transações extraídas
    let transacoes = [];


    // ==================================================
    // ESTRATÉGIA DUPLA DE EXTRAÇÃO
    // ==================================================

    /**
     * CASO 1:
     * A IA já retornou JSON estruturado:
     *
     * {
     *   output: [...]
     * }
     */
    if (item.output && Array.isArray(item.output)) {

        transacoes = item.output;

    }

    /**
     * CASO 2:
     * A IA retornou texto bruto.
     *
     * Então tentamos:
     * - localizar JSON dentro do texto;
     * - limpar pequenas corrupções;
     * - fazer parse manual.
     */
    else {

        let textoBruto =
          item.text ||
          item.message?.content ||
          "";

        /**
         * Alguns modelos retornam:
         * content[0].text
         */
        if (
          item.content &&
          Array.isArray(item.content) &&
          item.content[0]?.text
        ) {
            textoBruto = item.content[0].text;
        }

        // Se existe texto, tenta extrair JSON
        if (textoBruto) {

            /**
             * Busca conteúdo entre [] ou {}
             */
            const match =
              textoBruto.match(/[\{\[]([\s\S]*)[\}\]]/);

            if (match) {

                try {

                    let jsonLimpo = match[0];

                    /**
                     * Correções automáticas de JSON quebrado:
                     *
                     * - remove vírgulas sobrando
                     * - corrige fechamentos mal formados
                     */
                    jsonLimpo = jsonLimpo
                      .replace(/\},\s*}/g, '} ] }')
                      .replace(/,\s*([\]}])/g, '$1');

                    // Parse do JSON recuperado
                    const dadosParseados =
                      JSON.parse(jsonLimpo);

                    /**
                     * Compatibilidade com formatos:
                     * - transacoes
                     * - output
                     * - array direto
                     */
                    transacoes =
                      dadosParseados.transacoes ||
                      dadosParseados.output ||
                      (
                        Array.isArray(dadosParseados)
                          ? dadosParseados
                          : []
                      );

                } catch (parseErr) {

                    // Guarda erro de parse
                    relatorio_erros.push({
                      erro:
                        `Falha ao parsear string de texto na página ${i}`,
                      detalhe:
                        parseErr.message
                    });
                }
            }
        }
    }


    // ==================================================
    // VALIDAÇÃO DAS TRANSAÇÕES EXTRAÍDAS
    // ==================================================

    /**
     * Se não conseguiu extrair um array válido,
     * pula o item atual.
     */
    if (
      !Array.isArray(transacoes) ||
      transacoes.length === 0
    ) {

        relatorio_erros.push({
          aviso:
            `Não foi possível extrair transações estruturadas do item ${i}.`
        });

        continue;
    }


    // ==================================================
    // 3. NORMALIZAÇÃO DAS TRANSAÇÕES
    // ==================================================

    transacoes.forEach((t, index) => {

        // ==============================================
        // DESCRIÇÃO
        // ==============================================

        /**
         * Padroniza descrição:
         * - string
         * - uppercase
         * - trim
         */
        const descOriginal =
          (t.t || t.descricao || "")
            .toString()
            .toUpperCase()
            .trim();


        // ==============================================
        // VALOR
        // ==============================================

        /**
         * Aceita:
         * - t.v
         * - t.valor
         */
        const valorOriginal =
          parseFloat(
            t.v !== undefined
              ? t.v
              : t.valor
          ) || 0;


        /**
         * Determina sinal do valor:
         *
         * "-" ou "despesa"
         * => negativo
         *
         * "+" ou outros
         * => positivo
         */
        const sinal = t.s || t.tipo || "";

        let valorFinal =
          (
            sinal === "-" ||
            sinal.toLowerCase() === "despesa"
          )
            ? -Math.abs(valorOriginal)
            : Math.abs(valorOriginal);


        // ==============================================
        // DATA
        // ==============================================

        /**
         * Aceita:
         * - d
         * - data
         */
        let dataRaw =
          t.d || t.data || "";

        /**
         * Remove timezone/lixo
         */
        let dataISO =
          dataRaw.split('-')[0].trim();


        /**
         * Converte:
         * DD/MM/YYYY
         *
         * para:
         * YYYY-MM-DDT12:00:00
         */
        if (dataISO.includes('/')) {

            const pDate =
              dataISO.split('/');

            /**
             * Se não tiver ano,
             * usa ano atual
             */
            const anoLido =
              pDate[2]
                ? pDate[2].trim()
                : anoAtual;

            dataISO =
              `${anoLido}-${pDate[1].padStart(2,'0')}-${pDate[0].padStart(2,'0')}T12:00:00`;
        }


        // ==============================================
        // PARCELAMENTO
        // ==============================================

        /**
         * Aceita:
         * - p
         * - parcelamento
         */
        const p =
          t.p || t.parcelamento || null;


        // ==============================================
        // FILTRO DE DUPLICIDADE DE PARCELAS
        // ==============================================

        /**
         * Detecta padrões:
         * - 01/12
         * - 1 de 12
         * - 01-12
         */
        const matchParcela =
        (p || descOriginal)
          .match(/\b(\d{1,2})\s*(?:\/|-|de)\s*(\d{1,2})\b/i);


        if (matchParcela) {

            const pAtual =
              parseInt(matchParcela[1], 10);

            const pTotal =
              matchParcela[2];

            /**
             * Remove o trecho da parcela
             * da descrição para criar assinatura
             */
            const descLimpa =
              descOriginal
                .replace(
                  /\(?\s*\d+\s*(?:\/|-|de)\s*\d+\s*\)?/gi,
                  ''
                )
                .trim();

            /**
             * Assinatura única:
             * descrição + valor + total parcelas
             */
            const signature =
              `${descLimpa}_${valorFinal}_${pTotal}`;

            /**
             * Se já existe parcela mais recente,
             * ignora duplicada.
             */
            if (
              parcelamentosVistos.has(signature) &&
              pAtual >
              parcelamentosVistos.get(signature)
            ) return;

            parcelamentosVistos.set(signature, pAtual);
        }


        // ==============================================
        // CATEGORIA
        // ==============================================

        const categoriaAtual =
          t.c || t.categoria || "outros-gv";


        /**
         * Categorias consideradas neutras.
         *
         * Não representam despesa real.
         */
        const categoriasNeutras = [
            "reembolsos",
            "estorno",
            "pagamento-fatura-cartao",
            "transferencia-mesma-titularidade",
            "despesas-reembolsaveis",
            "reserva-emergencia",
            "projetos-vida",
            "independencia-financeira"
        ];


        // ==============================================
        // OBJETO FINAL NORMALIZADO
        // ==============================================

        resultadosFinais.push({

            json: {

                // ID da conta
                account_id:
                  infoConta.id,

                // Nome banco + conta
                Conta:
                  infoConta.nome,

                // Data lançamento
                Data_lancamento:
                  dataISO,

                // Descrição padronizada
                Descricao:
                  descOriginal,

                // Valor final já com sinal
                Valor:
                  valorFinal,

                /**
                 * Tipo:
                 * - neutro
                 * - despesa
                 */
                Tipo:
                  categoriasNeutras.includes(categoriaAtual)
                    ? "neutro"
                    : "despesa",

                // Categoria financeira
                Categoria:
                  categoriaAtual,

                // Parcelamento
                p: p,

                // ID único da conciliação OCR
                id_conciliacao:
                  `ocr-${i}-${index}`,

                // Data pagamento
                Data_pagamento:
                  dataISO,

                // Classificação espelhada
                Classificacao:
                  categoriaAtual
            }
        });
    });
}


// ======================================================
// 4. FILTRO DE RUÍDO FINANCEIRO
// ======================================================

/**
 * Remove linhas que não são transações reais:
 * - TOTAL
 * - SUBTOTAL
 * - RESUMO
 * etc
 */
const validos = resultadosFinais.filter(res => {

    const d = res.json.Descricao;

    const ignorar = [
      "TOTAL",
      "SUBTOTAL",
      "RESUMO",
      "PAGAMENTO EFETUADO",
      "SALDO ANTERIOR"
    ];

    return (
      !ignorar.some(p =>
        d === p ||
        d.startsWith(p + " ")
      ) &&
      d !== ""
    );
});


// ======================================================
// 5. RETORNO FINAL
// ======================================================

/**
 * Prioridade:
 *
 * 1. Retorna transações válidas
 * 2. Se não houver:
 *    retorna relatório de erros
 * 3. Se não houver nada:
 *    retorna aviso genérico
 */
if (validos.length > 0) {

    return validos;
}

return relatorio_erros.length > 0
  ? relatorio_erros.map(e => ({ json: e }))
  : [{ json: { aviso: "Nenhuma transação gerada." } }];

/**
 * NORMALIZADOR UNIVERSAL (PEGA TUDO O QUE CHEGAR)
 */

// 1. DADOS DA CONTA
let accountId = "";
let bankName = "";
try {
  const webhook = $('Recebe link do Supabase Storage').first().json;
  const webData = webhook.body || webhook;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
} catch (e) { bankName = "Banco"; }

// 2. CAPTURA DE DADOS (ABERTURA DE ENVELOPE)
let listaBruta = [];
const incomingData = $input.all();

for (const item of incomingData) {
  const data = item.json;

  // Tenta encontrar a lista de transações em qualquer lugar
  let alvo = data.output || data;

  if (Array.isArray(alvo)) {
    listaBruta = listaBruta.concat(alvo);
  } else if (typeof alvo === 'object' && (alvo.t || alvo.d)) {
    listaBruta.push(alvo);
  }
}

// 3. MAPEAMENTO
const anoAtual = new Date().getFullYear();

const final = listaBruta.map((item, index) => {
  const desc = (item.t || "").toString().toUpperCase().trim();
  let v = item.v !== undefined ? item.v : 0;

  if (typeof v === 'string') v = v.replace(/[R$\s]/ig, '').replace(',', '.');
  let valorFinal = parseFloat(v) || 0;

  if (item.s === "-" || item.s === "despesa") valorFinal = -Math.abs(valorFinal);
  else valorFinal = Math.abs(valorFinal);

  let dataF = item.d || "";
  if (dataF.includes('/')) {
    let p = dataF.split('/');
    dataF = `${p[2] || anoAtual}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}T12:00:00`;
  }

  return {
    json: {
      account_id: accountId,
      Conta: bankName,
      Data_lancamento: dataF,
      Data_pagamento: dataF,
      Descricao: desc,
      Valor: valorFinal,
      Tipo: valorFinal < 0 ? "despesa" : (["reembolsos", "estorno","pagamento-fatura-cartao", "transferencia-mesma-titularidade", "despesas-reembolsaveis", "reserva-emergencia", "projetos-vida", "independencia-financeira"].includes(item.c) ? "neutro" : "receita"),
      Categoria: item.c || "outros-gv",
      id_conciliacao: `${desc}-${valorFinal}-${index}`
    }
  };
});

return final;

// 1. Buscamos o binário diretamente do nó que processou o arquivo original
// Se o nó que criou o binário tiver outro nome, ajuste 'Code in JavaScript10' abaixo
const nodeComArquivo = 'Code in JavaScript6'; 

let binaryData;
try {
    binaryData = await this.helpers.getBinaryDataBuffer(0, 'data', nodeComArquivo);
} catch (e) {
    // Caso o nome acima esteja diferente, tentamos pegar do que entrar no nó
    binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
}

if (!binaryData) {
    throw new Error("Arquivo binário não encontrado. Verifique se o nome do nó de origem está correto.");
}

const rawText = binaryData.toString('utf8');

// 2. O restante do seu processamento OFX
const trnRegex = /<STMTTRN>([\s\S]*?)<\/STMTTRN>/g;
const transactions = [];
let match;

while ((match = trnRegex.exec(rawText)) !== null) {
    const block = match[1];

    const getValue = (tag) => {
        const r = new RegExp(`<${tag}>([^<\\n\\r]+)`, 'i');
        const m = block.match(r);
        return m ? m[1].trim() : null;
    };

    const dateRaw = getValue('DTPOSTED');
    const amountStr = getValue('TRNAMT');
    const amount = parseFloat(amountStr);

    if (dateRaw && amountStr) {
        transactions.push({
            json: {
                d: `${dateRaw.substring(6,8)}/${dateRaw.substring(4,6)}/${dateRaw.substring(0,4)}`,
                t: getValue('MEMO') || getValue('NAME') || "TRANSACAO OFX",
                v: Math.abs(amount),
                s: amount < 0 ? '-' : '+',
                c: null
            }
        });
    }
}

return transactions;

/**
 * EXTRATOR + NORMALIZADOR UNIVERSAL
 * - Extrai transações do markdown/OCR
 * - Normaliza para o formato final do banco de dados
 */

// ========================================
// 1. DADOS DA CONTA
// ========================================

let accountId = "";
let bankName = "";

try {
  const webhook = $('Recebe link do Supabase Storage').first().json;
  const webData = webhook.body || webhook;

  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
} catch (e) {
  bankName = "Banco";
}

// ========================================
// 2. CONFIGURAÇÃO DE MESES
// ========================================

const meses = {
  "janeiro": "01",
  "fevereiro": "02",
  "março": "03",
  "abril": "04",
  "maio": "05",
  "junho": "06",
  "julho": "07",
  "agosto": "08",
  "setembro": "09",
  "outubro": "10",
  "novembro": "11",
  "dezembro": "12"
};

// ========================================
// 3. EXTRAÇÃO DAS TRANSAÇÕES
// ========================================

const inputData = $input.all();
const listaBruta = [];

for (const item of inputData) {

  // Tenta pegar texto de qualquer campo possível
  const textoBruto =
    item.json.markdown ||
    item.json.extractedText ||
    item.json.text ||
    "";

  // Caso já venha estruturado
  if (Array.isArray(item.json.output)) {
    listaBruta.push(...item.json.output);
    continue;
  }

  const linhas = textoBruto.split('\n');

  let dataVigente = null;

  for (let linha of linhas) {

    linha = linha.trim();

    if (!linha) continue;

    // ========================================
    // IGNORA LINHAS IRRELEVANTES
    // ========================================

    if (
      linha.includes("SAC:") ||
      linha.includes("Ouvidoria:") ||
      linha.includes("Deficiência") ||
      linha.includes("Fale com a gente")
    ) {
      continue;
    }

    // ========================================
    // DETECTA CABEÇALHO DE DATA
    // Ex: "16 de Janeiro de 2026"
    // ========================================

    const regexData = /(\d{1,2})\s+de\s+([a-zA-Zçãó]+)\s+de\s+(\d{4})/i;

    const matchData = linha.match(regexData);

    if (matchData) {

      const dia = matchData[1].padStart(2, '0');
      const mesTexto = matchData[2].toLowerCase();
      const ano = matchData[3];

      const mes = meses[mesTexto] || "01";

      dataVigente = `${dia}/${mes}/${ano}`;

      continue;
    }

    // ========================================
    // CAPTURA LINHAS DE TABELA MARKDOWN
    // ========================================

    if (
      linha.startsWith('|') &&
      !linha.includes('---') &&
      !linha.includes('Saldo total') &&
      !linha.includes('Valor |')
    ) {

      const colunas = linha
        .split('|')
        .map(c => c.trim())
        .filter(c => c !== "");

      if (colunas.length >= 2) {

        const descricaoBruta = colunas[0];
        const valorBruto = colunas[1];

        // ========================================
        // NORMALIZA VALOR
        // ========================================

        let valorTexto = valorBruto
          .replace(/[R$\s\.]/g, '')
          .replace(',', '.');

        let valor = parseFloat(valorTexto) || 0;

        const sinal = valor < 0 ? '-' : '+';

        valor = Math.abs(valor);

        // ========================================
        // SALVA TRANSAÇÃO
        // ========================================

        if (dataVigente && descricaoBruta) {

          listaBruta.push({
            d: dataVigente,
            t: descricaoBruta.replace(/"/g, '').trim(),
            v: valor,
            s: sinal
          });

        }
      }
    }
  }
}

// ========================================
// 4. NORMALIZAÇÃO FINAL
// ========================================

const anoAtual = new Date().getFullYear();

const final = listaBruta.map((item, index) => {

  const desc = (item.t || "")
    .toString()
    .toUpperCase()
    .trim();

  let v = item.v !== undefined ? item.v : 0;

  if (typeof v === 'string') {
    v = v
      .replace(/[R$\s]/ig, '')
      .replace(',', '.');
  }

  let valorFinal = parseFloat(v) || 0;

  // ========================================
  // APLICA SINAL
  // ========================================

  if (
    item.s === "-" ||
    item.s === "despesa"
  ) {
    valorFinal = -Math.abs(valorFinal);
  } else {
    valorFinal = Math.abs(valorFinal);
  }

  // ========================================
  // NORMALIZA DATA
  // dd/mm/yyyy -> yyyy-mm-dd
  // ========================================

  let dataF = item.d || "";

  if (dataF.includes('/')) {

    const p = dataF.split('/');

    dataF = `${p[2] || anoAtual}-${p[1].padStart(2, '0')}-${p[0].padStart(2, '0')}T12:00:00`;
  }

  // ========================================
  // DEFINE TIPO
  // ========================================

  const categoriasNeutras = [
    "reembolsos",
    "estorno",
    "pagamento-fatura-cartao",
    "transferencia-mesma-titularidade",
    "despesas-reembolsaveis",
    "reserva-emergencia",
    "projetos-vida",
    "independencia-financeira"
  ];

  const tipo =
    valorFinal < 0
      ? "despesa"
      : categoriasNeutras.includes(item.c)
        ? "neutro"
        : "receita";

  // ========================================
  // RETORNO FINAL
  // ========================================

  return {
    json: {
      account_id: accountId,
